// @mui
import { styled } from '@mui/material/styles'
import { useEffect, useState, useRef } from 'react'
// components
import Page from 'src/components/Page'
// sections
import { Box, Button, Typography, IconButton } from '@mui/material'

import Container from 'src/components/Layout/Container'
import Content from 'src/components/Layout/Content'
import Header from 'src/components/Layout/Header'
import { useNavigate, useLocation } from 'react-router'

import { useDispatch, useSelector } from 'react-redux'

import LabeledInput from 'src/components/core/LabeledInput'

import ExerciseCard from 'src/components/instructor/exerciseCard'

import { useOutletContext } from 'react-router-dom'
import { computePath } from 'src/utils/routepath'
import { deleteVideos } from 'src/redux/actions/createProgram'
import { TransitionGroup } from 'react-transition-group'
import { addWorkout } from 'src/redux/actions/figgsLibrary'
import Collapse from '@mui/material/Collapse'
import ArrowLeft from 'src/assets/IconSet/ArrowLeft'
import _ from 'lodash'
const RootStyle = styled('div')(() => ({
    backgroundColor: '#F2F5F9',
    height: '100%',
}))

const BoxHeader = styled(Box)(() => ({
    width: '100%',
    zIndex: 100,
    backgroundColor: '#fff',
    boxShadow: '0px 4px 54px rgba(225, 231, 240, 0.5)',
    borderRadius: '0px 0px 8px 8px',
}))
// ----------------------------------------------------------------------

export default function WorkoutDay() {
    const dispatch = useDispatch()
    const { state } = useLocation()
    const [workoutData, setWorkoutData] = useOutletContext()

    const navigate = useNavigate()
    const reference = useRef(null)
    reference.current = {}

    const handleAddWorkout = () => {
        dispatch(addWorkout(workoutData)).then((result) => {
            navigate(-1)
        })
    }

    const addNewDay = () => {
        let plan = { ...workoutData }

        plan.Exercise.push({
            url: '',
            title: '',
            reps: null,
            sets: null,
            note: '',
            rest: null,
            banner: null,
            isNew: true,
        })
        reference.current = plan
        let contentElement = document.getElementById('circled-content')

        setTimeout(() => {
            contentElement.scrollTo({
                top: contentElement.scrollHeight,
                behavior: 'smooth',
            })
        }, 500)

        setWorkoutData(plan)
    }

    const editDay = (data) => {
        let plan = { ...workoutData }
        plan = {
            ...plan,
            ...data,
        }
        reference.current = plan
        setWorkoutData(plan)
    }

    const deleteExercise = (id) => {
        let plan = { ...workoutData }
        let delEx = plan.Exercise.splice(id, 1)
        let urls = delEx?.[0]?.media?.map((i) => {
            return i.split('https://vimeo.com/')[1]
        })
        if (urls)
            dispatch(deleteVideos(urls))
                .then((res) => {
                    reference.current = plan
                    setWorkoutData(plan)
                })
                .catch((err) => {
                    if (err.response.status == 404) {
                        reference.current = plan
                        setWorkoutData(plan)
                    }
                })
        else {
            reference.current = plan
            setWorkoutData(plan)
        }
    }

    const editExercise = (val, index) => {
        let plan = { ...workoutData }
        plan.Exercise[index] = {
            ...plan.Exercise[index],
            ...val,
        }
        reference.current = plan
        setWorkoutData(plan)
    }

    const uploadNewMedia = (e, i) => {
        navigate('/library/addmedia', {
            state: {
                file: e.target.files,
                index: i,
                workoutId: workoutData._id,
            },
        })
    }
    const uploadMediasFromLib = (val, index) => {
        let media = [
            ...(workoutData.Exercise[index]?.media || []),
            ...val.map((i) => i.media),
        ]
        let triggerMuscle = _.union(
            workoutData.Exercise[index]?.triggerMuscle,
            ...val.map((i) => i.triggerMuscle)
        )

        editExercise({ media: media, triggerMuscle: triggerMuscle }, index)
    }

    return (
        <RootStyle>
            <Page title=" Simplified Online Fitness Training ">
                <Container>
                    {' '}
                    <Header noColor>
                        <BoxHeader px={2} py={2}>
                            <Box
                                width={'100%'}
                                display={'flex'}
                                alignItems={'center'}
                                flexDirection={'row'}
                                justifyContent={'space-between'}
                            >
                                <Box
                                    display={'flex'}
                                    alignItems={'center'}
                                    flexDirection={'row'}
                                >
                                    <IconButton
                                        onClick={() =>
                                            navigate(-1, {
                                                replace: true,
                                                state: { tab: 1, sds: 2 },
                                            })
                                        }
                                        sx={{ color: 'text.primary' }}
                                    >
                                        <ArrowLeft />
                                    </IconButton>
                                    <Typography
                                        variant="body1"
                                        color="text.primary"
                                    >
                                        {/* Week {state?.week + 1} &gt; */}
                                        <Typography
                                            component={'span'}
                                            color="text.primary"
                                        >
                                            Create workout
                                            {/* &nbsp;{days[state?.day]} */}
                                        </Typography>
                                    </Typography>
                                </Box>
                                <Button
                                    sx={{ px: 0 }}
                                    onClick={() => handleAddWorkout()}
                                >
                                    Done
                                </Button>
                            </Box>
                        </BoxHeader>
                    </Header>{' '}
                    <Content
                        style={{
                            paddingTop: 16,
                            paddingBottom: 16,
                            overflowY: 'auto',
                        }}
                    >
                        <LabeledInput
                            fullWidth
                            placeholder="Example: Chest day"
                            clabel="Workout title"
                            onChange={(e) => editDay({ Title: e.target.value })}
                            name={'title'}
                            value={workoutData?.Title}
                            InputProps={{
                                style: {
                                    backgroundColor: 'white',
                                    boxShadow:
                                        '0px 4px 54px rgb(225 231 240 / 50%)',
                                },
                            }}
                        />

                        <TransitionGroup>
                            {workoutData.Exercise.map((step, index) => (
                                <Collapse key={index}>
                                    <Box>
                                        <center>
                                            {/* <Divider
                        sx={{ my: 2, mt: 3, variant: "middle", width: 120 }}
                        variant={"middle"}
                      /> */}
                                            <Typography
                                                color="text.secondary"
                                                sx={{
                                                    fontSize: 18,
                                                    color: '#95A3B8',
                                                    my: 2,
                                                }}
                                            >
                                                Exercise {index + 1}
                                            </Typography>
                                        </center>

                                        <ExerciseCard
                                            viewMode={false}
                                            mode={'create'}
                                            individualWorkout
                                            onMediaClick={(vi) =>
                                                navigate('/library/addmedia', {
                                                    state: {
                                                        index: index,
                                                        videoIndex: vi,
                                                    },
                                                })
                                            }
                                            Program={{}}
                                            _id={workoutData._id}
                                            updateProgram={() => {
                                                console.log('program updated')
                                            }}
                                            w={0}
                                            onUploadNewMedia={(e) =>
                                                uploadNewMedia(
                                                    e,

                                                    index
                                                )
                                            }
                                            d={0}
                                            index={index}
                                            newCard={step.isNew || !step.title}
                                            deleteExercise={() =>
                                                deleteExercise(index)
                                            }
                                            editExercise={(val) =>
                                                editExercise(val, index)
                                            }
                                            uploadMediasFromLib={(val) =>
                                                uploadMediasFromLib(val, index)
                                            }
                                            plan={workoutData.Exercise[index]}
                                        />
                                    </Box>
                                </Collapse>
                            ))}
                        </TransitionGroup>

                        {/* <center>
              <Divider
                sx={{ mt: 2, variant: "middle", width: 120 }}
                variant={"middle"}
              />
            </center> */}
                        <Box
                            display={'flex'}
                            alignItems={'center'}
                            size={'small'}
                            sx={{ mr: 0, ml: 0, mt: 2 }}
                        >
                            <Button
                                fullWidth
                                variant="contained"
                                size={'small'}
                                disabled={!workoutData?.Title}
                                sx={{
                                    display: 'flex',
                                    justifyContent: 'center',
                                    mt: 2,
                                    fontSize: 16,
                                }}
                                onClick={() => addNewDay()}
                            >
                                Add exercise
                            </Button>
                        </Box>
                    </Content>
                </Container>{' '}
            </Page>
        </RootStyle>
    )
}
